function setLang(code){CL=code;localStorage.setItem('bat-op-lang',code);document.getElementById('lm').classList.remove('open');document.getElementById('lang-btn').setAttribute('aria-expanded','false');document.getElementById('lang-label').textContent=code.toUpperCase();document.querySelectorAll('.lo').forEach((el,i)=>{const c=['pt','en','es','de','ru'];el.classList.toggle('active',c[i]===code)});applyTR();renderAll()}
function updateLangUI(){document.getElementById('lang-label').textContent=CL.toUpperCase();document.querySelectorAll('.lo').forEach((el,i)=>{const c=['pt','en','es','de','ru'];el.classList.toggle('active',c[i]===CL)})}
function applyTR(){document.querySelectorAll('[data-i18n]').forEach(el=>{const k=el.getAttribute('data-i18n');const v=T(k);if(v)el.textContent=v});document.querySelectorAll('[data-i18n-ph]').forEach(el=>{const k=el.getAttribute('data-i18n-ph');const v=T(k);if(v)el.placeholder=v});document.documentElement.lang=CL==='pt'?'pt-BR':CL==='ru'?'ru':CL==='de'?'de':CL==='es'?'es':'en'}
function toggleLangMenu(){const open=document.getElementById('lm').classList.toggle('open');document.getElementById('lang-btn').setAttribute('aria-expanded',open)}
