function initNotifs(){const unread=notifs.filter(n=>n.unread).length;const dot=document.getElementById('notif-dot');if(dot)dot.style.display=unread?'':'none';renderNotifs()}

/* ============================================================ BADGES */
function prioBadge(p){const m={alta:{c:'alta',l:T('prio_high')},media:{c:'media',l:T('prio_med')},baixa:{c:'baixa',l:T('prio_low')}};const s=m[p]||{c:p,l:p};return`<span class="prio-badge ${s.c}"><span style="width:5px;height:5px;border-radius:50%;display:inline-block;${p==='alta'?'background:var(--dn)':p==='media'?'background:var(--wn)':'background:var(--bm)'}"></span>${s.l}</span>`}
function stBadge(s){const m={aberto:{c:'aberto',l:T('status_open'),i:'fa-clock'},atendimento:{c:'atendimento',l:T('status_atend'),i:'fa-rotate'},finalizado:{c:'finalizado',l:T('status_done'),i:'fa-check'},urgente:{c:'urgente',l:T('status_urg'),i:'fa-fire'}};const st=m[s]||{c:s,l:s,i:'fa-circle'};return`<span class="stbadge ${st.c}"><i class="fa-solid ${st.i}" style="font-size:9px"></i>${st.l}</span>`}

/* ============================================================ COUNTERS */
function animV(el,tgt){if(!el)return;const from=parseInt(el.textContent)||0;const dur=700;const st=performance.now();function step(now){const p=Math.min((now-st)/dur,1);const e=1-Math.pow(1-p,3);el.textContent=Math.round(from+(tgt-from)*e);if(p<1)requestAnimationFrame(step)}requestAnimationFrame(step)}
function updateStats(){
  const active=tickets.filter(t=>t.status!=='finalizado');
  const op=tickets.filter(t=>t.status==='aberto').length;
  const at=tickets.filter(t=>t.status==='atendimento').length;
  const dn=tickets.filter(t=>t.status==='finalizado').length;
  const ug=tickets.filter(t=>t.priority==='alta'&&t.status!=='finalizado').length;
  animV(document.getElementById('cnt-open'),op);
  animV(document.getElementById('cnt-atend'),at);
  animV(document.getElementById('cnt-done'),dn);
  animV(document.getElementById('cnt-urg'),ug);
  document.getElementById('nb-open').textContent=op+at;
  // profile stats
  const po=document.getElementById('pstat-open');if(po)po.textContent=op;
  const pa=document.getElementById('pstat-atend');if(pa)pa.textContent=at;
  const pd=document.getElementById('pstat-done');if(pd)pd.textContent=dn;
}

/* ============================================================ CHARTS */
const BAR_COLORS=['#005691','#2D9E6B','#E8A020','#6B46C1','#C8A96B','#E53E3E'];
function renderBarChart(){
  const sectors={};
  tickets.filter(t=>t.status!=='finalizado').forEach(t=>{sectors[t.sector]=(sectors[t.sector]||0)+1});
  const entries=Object.entries(sectors).sort((a,b)=>b[1]-a[1]).slice(0,6);
  const max=Math.max(...entries.map(e=>e[1]),1);
  const bc=document.getElementById('bar-chart');
  bc.innerHTML=entries.map(([sec,val],i)=>{
    const pct=Math.round((val/max)*180);
    const short=sec.length>10?sec.substring(0,8)+'…':sec;
    return`<div class="bar-col"><span class="bar-val">${val}</span><div class="bar" title="${sec}: ${val}" style="height:${pct}px;background:${BAR_COLORS[i%BAR_COLORS.length]}" aria-label="${sec}: ${val} chamados"></div><span class="bar-label">${short}</span></div>`;
  }).join('');
  setTimeout(()=>{bc.querySelectorAll('.bar').forEach(b=>{b.style.opacity='0';b.style.opacity='1'})},50);
}
function renderDonut(){
  const alta=tickets.filter(t=>t.priority==='alta'&&t.status!=='finalizado').length;
  const media=tickets.filter(t=>t.priority==='media'&&t.status!=='finalizado').length;
  const baixa=tickets.filter(t=>t.priority==='baixa'&&t.status!=='finalizado').length;
  const total=alta+media+baixa;
  document.getElementById('donut-total').textContent=total;
  const C=2*Math.PI*70;
  function dashOff(val,start){return C-C*(val/Math.max(total,1));}
  const arcs=[
    {id:'arc-alta',val:alta,offset:0},
    {id:'arc-media',val:media,offset:(alta/Math.max(total,1))*C},
    {id:'arc-baixa',val:baixa,offset:((alta+media)/Math.max(total,1))*C},
  ];
  arcs.forEach(a=>{const el=document.getElementById(a.id);if(!el)return;el.style.strokeDashoffset=C-C*(a.val/Math.max(total,1));el.style.strokeDasharray=`${C*(a.val/Math.max(total,1))} ${C}`;el.setAttribute('stroke-dashoffset',C-C*(a.val/Math.max(total,1))-a.offset)});
  // Rebuild as a proper segmented donut
  const svgEl=document.querySelector('#donut-wrap svg');
  if(!svgEl)return;
  svgEl.innerHTML='<circle cx="90" cy="90" r="70" fill="none" stroke="var(--br)" stroke-width="24"/>';
  const colors=[{c:'var(--dn)',v:alta,l:T('prio_high')},{c:'var(--wn)',v:media,l:T('prio_med')},{c:'var(--bm)',v:baixa,l:T('prio_low')}];
  let offset=0;
  colors.forEach(({c,v,l})=>{
    if(!v)return;
    const pct=v/Math.max(total,1);
    const arc=document.createElementNS('http://www.w3.org/2000/svg','circle');
    arc.setAttribute('cx','90');arc.setAttribute('cy','90');arc.setAttribute('r','70');
    arc.setAttribute('fill','none');arc.setAttribute('stroke',c);arc.setAttribute('stroke-width','24');
    arc.setAttribute('stroke-dasharray',`${pct*C} ${C}`);
    arc.setAttribute('stroke-dashoffset',-(offset*C));
    arc.setAttribute('aria-label',`${l}: ${v}`);
    arc.style.transition='stroke-dashoffset 1.2s ease';
    svgEl.appendChild(arc);
    offset+=pct;
  });
  // Legend
  const leg=document.getElementById('donut-legend');
  if(leg)leg.innerHTML=colors.filter(x=>x.v>0).map(({c,v,l})=>`<div class="dl-item"><span class="dl-dot" style="background:${c}"></span>${l}<strong>${v}</strong></div>`).join('');
}

