/* ============================================================ MY TICKETS */
let mtPage=1;const PER=6;
function getMTFiltered(){
  const q=(document.getElementById('mt-search')?.value||'').toLowerCase();
  const p=document.getElementById('mt-prio')?.value||'';
  const s=document.getElementById('mt-status')?.value||'';
  const sec=document.getElementById('mt-sector')?.value||'';
  return tickets.filter(t=>t.status!=='finalizado'&&(!q||(t.id+t.equip+t.sector+t.problem).toLowerCase().includes(q))&&(!p||t.priority===p)&&(!s||t.status===s)&&(!sec||t.sector===sec));
}
function renderMyTickets(){
  const d=TR[CL]||TR.pt;
  const fi=getMTFiltered();const tot=fi.length;
  const tp=Math.max(1,Math.ceil(tot/PER));if(mtPage>tp)mtPage=1;
  const st=(mtPage-1)*PER;const pg=fi.slice(st,st+PER);
  document.getElementById('mt-tbody').innerHTML=pg.map(t=>`<tr>
    <td style="font-family:monospace;font-size:11px;color:var(--mu)">${t.id}</td>
    <td style="font-size:12.5px;font-weight:600;max-width:140px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" title="${t.equip}">${t.equip}</td>
    <td style="font-size:12px">${t.sector}</td>
    <td style="font-size:12px;max-width:180px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:var(--mu)" title="${t.problem}">${t.problem}</td>
    <td>${prioBadge(t.priority)}</td>
    <td>${stBadge(t.status)}</td>
    <td style="font-size:12px;color:var(--mu)">${t.tech||T('no_tech')}</td>
    <td style="font-size:11px;color:var(--mu)">${t.date}</td>
    <td><button class="btn primary xs" onclick="viewTicket('${t.id}')" aria-label="Ver detalhes ${t.id}"><i class="fa-solid fa-eye" aria-hidden="true"></i>${T('btn_view')}</button></td>
  </tr>`).join('');
  document.getElementById('mt-count').textContent=`${d.showing} ${Math.min(st+1,tot)}-${Math.min(st+PER,tot)} ${d.of} ${tot} ${d.records}`;
  renderPag('mt-pag-info','mt-pag-btns',tot,tp,'mt');
}
function renderHistory(){
  const d=TR[CL]||TR.pt;
  const q=(document.getElementById('hist-search')?.value||'').toLowerCase();
  const p=document.getElementById('hist-prio')?.value||'';
  const fi=tickets.filter(t=>t.status==='finalizado'&&(!q||(t.id+t.equip+t.sector).toLowerCase().includes(q))&&(!p||t.priority===p));
  const tot=fi.length;
  document.getElementById('hist-tbody').innerHTML=fi.map(t=>`<tr>
    <td style="font-family:monospace;font-size:11px;color:var(--mu)">${t.id}</td>
    <td style="font-size:12.5px;font-weight:600">${t.equip}</td>
    <td style="font-size:12px">${t.sector}</td>
    <td>${prioBadge(t.priority)}</td>
    <td style="font-size:12px;color:var(--mu)">${t.tech||'—'}</td>
    <td style="font-size:11px;color:var(--mu)">${t.dateEnd||t.date}</td>
    <td><button class="btn outline xs" onclick="viewTicket('${t.id}')" aria-label="Ver detalhes ${t.id}"><i class="fa-solid fa-eye" aria-hidden="true"></i>${T('view_detail')}</button></td>
  </tr>`).join('');
  document.getElementById('hist-count').textContent=`${d.showing} ${tot} ${d.records}`;
  renderPag('hist-pag-info','hist-pag-btns',tot,Math.max(1,Math.ceil(tot/PER)),'hist');
}
function renderPag(infoId,btnsId,tot,tp,prefix){
  const d=TR[CL]||TR.pt;const page=prefix==='mt'?mtPage:1;
  const pi=document.getElementById(infoId);const pb=document.getElementById(btnsId);
  if(!pi||!pb)return;
  const st=(page-1)*PER;
  pi.innerHTML=`${d.showing} <strong>${Math.min(st+1,tot)}–${Math.min(st+PER,tot)}</strong> ${d.of} <strong>${tot}</strong>`;
  let h=`<button class="pp" onclick="changePage('${prefix}',${page-1})" ${page<=1?'disabled':''} aria-label="Anterior"><i class="fa-solid fa-chevron-left" aria-hidden="true"></i></button>`;
  for(let i=1;i<=tp;i++){if(i===1||i===tp||Math.abs(i-page)<=1){h+=`<button class="pp ${i===page?'act':''}" onclick="changePage('${prefix}',${i})">${i}</button>`}else if(Math.abs(i-page)===2){h+=`<span class="pp" style="cursor:default">…</span>`}}
  h+=`<button class="pp" onclick="changePage('${prefix}',${page+1})" ${page>=tp?'disabled':''} aria-label="Próxima"><i class="fa-solid fa-chevron-right" aria-hidden="true"></i></button>`;
  pb.innerHTML=h;
}
function changePage(prefix,page){if(prefix==='mt'){const fi=getMTFiltered();const tp=Math.max(1,Math.ceil(fi.length/PER));if(page<1||page>tp)return;mtPage=page;renderMyTickets()}}

/* ============================================================ TICKET DETAIL */
function viewTicket(id){
  const t=tickets.find(x=>x.id===id);if(!t)return;
  document.getElementById('modal-view-title').textContent=`${t.id} — ${t.equip}`;
  document.getElementById('mv-sub').textContent=t.sector;
  document.getElementById('mv-body').innerHTML=`
    <div style="display:grid;grid-template-columns:auto 1fr;gap:10px 20px;font-size:13px;margin-bottom:16px">
      <span style="font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--mu);padding-top:2px">${T('col_equip')}</span><span style="color:var(--tx);font-weight:600">${t.equip}</span>
      <span style="font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--mu);padding-top:2px">${T('col_sector')}</span><span>${t.sector}</span>
      <span style="font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--mu);padding-top:2px">${T('col_priority')}</span><span>${prioBadge(t.priority)}</span>
      <span style="font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--mu);padding-top:2px">Status</span><span>${stBadge(t.status)}</span>
      <span style="font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--mu);padding-top:2px">${T('col_tech')}</span><span>${t.tech||T('no_tech')}</span>
      <span style="font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--mu);padding-top:2px">${T('col_date')}</span><span>${t.date}</span>
      ${t.dateEnd?`<span style="font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--mu);padding-top:2px">${T('col_date_end')}</span><span style="color:var(--ok);font-weight:600">${t.dateEnd}</span>`:''}
    </div>
    <div style="background:var(--sf2);border-radius:9px;padding:14px;border-left:3px solid var(--bm);border:1px solid var(--br)">
      <p style="font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--mu);margin-bottom:8px">${T('col_problem')}</p>
      <p style="font-size:13px;color:var(--tm);line-height:1.7">${t.problem}</p>
    </div>`;
  document.getElementById('modal-view').classList.add('open');
}

/* ============================================================ NEW TICKET */
async function submitTicket(){
  const sector=document.getElementById('nc-sector').value;
  const priority=document.getElementById('nc-priority').value;
  const equip=document.getElementById('nc-equip').value.trim();
  const problem=document.getElementById('nc-problem').value.trim();
  const cat=document.getElementById('nc-cat').value;
  if(!equip||!problem){showToast('Preencha todos os campos.','err');return}
  try{
    await API.criar({operadorId:currentUser.id,setor:sector,maquina:equip,categoria:cat,prioridade:priority.toUpperCase(),descricao:problem});
    closeModal('modal-new');
    document.getElementById('nc-equip').value='';document.getElementById('nc-problem').value='';
    await loadData();renderAll();
    showToast(T('toast_ticket_created'),'suc');
  }catch(e){showToast('Erro ao criar chamado: '+e.message,'err')}
}

/* ============================================================ USER */
function updateOpName(v){
  opUser.name=v;localStorage.setItem('bat-op-name',v);
  const iv=ini(v);
  ['sb-av','hdr-av','prof-av'].forEach(id=>{const el=document.getElementById(id);if(el)el.textContent=iv});
  ['sb-name','hdr-name','prof-name'].forEach(id=>{const el=document.getElementById(id);if(el)el.textContent=v});
}
function saveProfile(){
  const name=document.getElementById('pf-name').value.trim();
  const email=document.getElementById('pf-email').value.trim();
  if(name){updateOpName(name);localStorage.setItem('bat-op-name',name)}
  if(email){opUser.email=email;localStorage.setItem('bat-op-email',email);const pe=document.getElementById('prof-email');if(pe)pe.textContent=email}
  showToast(T('toast_profile_saved'),'suc');
}

/* ============================================================ ACCESSIBILITY */
function toggleHC(cb){document.documentElement.setAttribute('data-hc',cb.checked?'1':'0');localStorage.setItem('bat-op-hc',cb.checked?'1':'0');toggleA11y('a11y-hc',cb)}
function toggleA11y(id,cb){document.getElementById(id)?.classList.toggle('on',cb.checked)}
function toggleReduceMotion(cb){const v=cb.checked?'.01ms':'';['--tr'].forEach(p=>document.documentElement.style.setProperty(p,cb.checked?'0s':''));if(cb.checked){const s=document.createElement('style');s.id='rm-style';s.textContent='*,*::before,*::after{animation-duration:.01ms!important;transition-duration:.01ms!important}';document.head.appendChild(s)}else{const s=document.getElementById('rm-style');if(s)s.remove()}localStorage.setItem('bat-op-rm',cb.checked?'1':'0');toggleA11y('a11y-rm',cb)}
function toggleBigFont(cb){document.documentElement.style.fontSize=cb.checked?'18px':'';localStorage.setItem('bat-op-bf',cb.checked?'1':'0');toggleA11y('a11y-font',cb)}
function changeFontSize(v){document.documentElement.style.setProperty('--font-scale-val',v);document.documentElement.style.fontSize=`calc(16px * ${v})`;document.getElementById('font-val').textContent=Math.round(v*100)+'%';localStorage.setItem('bat-op-fs',v)}
function restoreA11y(){
  const hc=localStorage.getItem('bat-op-hc');if(hc==='1'){document.documentElement.setAttribute('data-hc','1');const sw=document.getElementById('sw-hc');if(sw){sw.checked=true;toggleA11y('a11y-hc',sw)}}
  const rm=localStorage.getItem('bat-op-rm');if(rm==='1'){const sw=document.getElementById('sw-rm');if(sw){sw.checked=true;toggleReduceMotion(sw)}}
  const bf=localStorage.getItem('bat-op-bf');if(bf==='1'){const sw=document.getElementById('sw-font');if(sw){sw.checked=true;toggleBigFont(sw)}}
  const fs=localStorage.getItem('bat-op-fs');if(fs){document.documentElement.style.fontSize=`calc(16px * ${fs})`;const fr=document.getElementById('font-range');if(fr)fr.value=fs;const fv=document.getElementById('font-val');if(fv)fv.textContent=Math.round(fs*100)+'%'}
}

/* ============================================================ RENDER ALL */
function renderAll(){applyTR();updateStats();renderDashTable();renderBarChart();renderDonut();renderTL();renderMyTickets();renderHistory();renderNotifs()}

/* ============================================================ INIT */
async function init(){
  initTheme();initLang();restoreA11y();
  await loadSession();
  if(currentUser&&currentUser.nome){
    opUser.name=currentUser.nome;
    if(currentUser.email)opUser.email=currentUser.email;
  }
  await loadData();
  const n=opUser.name;const iv=ini(n);
  ['sb-av','hdr-av','prof-av'].forEach(id=>{const el=document.getElementById(id);if(el)el.textContent=iv});
  ['sb-name','hdr-name','prof-name'].forEach(id=>{const el=document.getElementById(id);if(el)el.textContent=n});
  const pe=document.getElementById('prof-email');if(pe)pe.textContent=opUser.email;
  const pni=document.getElementById('pf-name');if(pni)pni.value=n;
  const pei=document.getElementById('pf-email');if(pei)pei.value=opUser.email;
  document.getElementById('dash-greet').textContent=`${T('btn_new_ticket')}: ${tickets.filter(t=>t.status!=='finalizado').length} ${T('stat_open')}`;
  initNotifs();renderAll();
}
document.addEventListener('DOMContentLoaded',init);

